--
-- Table structure for table `caipiao_moneylog`
--

DROP TABLE IF EXISTS `caipiao_moneylog`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `caipiao_moneylog` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT COMMENT 'bản ghiID',
  `uid` bigint(20) NOT NULL COMMENT 'ID người dùng',
  `username` varchar(60) NOT NULL COMMENT 'Người dùng',
  `type` tinyint(4) NOT NULL DEFAULT '0' COMMENT 'Loại: 1=nạp tiền,2=rút tiền,3=đặt cược,4=trúng thưởng,5=hoàn cược,6=hoa hồng,7=Hoạt động,8=,9=,10=cược nhómtham gia,11=cược nhómtrúng thưởng',
  `typename` varchar(50) NOT NULL COMMENT 'Loạitên',
  `trano` varchar(100) DEFAULT '' COMMENT 'mã giao dịch',
  `amount` decimal(18,2) NOT NULL DEFAULT '0.00' COMMENT 'Số tiền(,)',
  `before` decimal(18,2) NOT NULL DEFAULT '0.00' COMMENT 'Số dư',
  `after` decimal(18,2) NOT NULL DEFAULT '0.00' COMMENT 'Số dư',
  `remark` varchar(500) DEFAULT '' COMMENT 'Ghi chúmô tả',
  `addtime` bigint(20) NOT NULL DEFAULT '0' COMMENT 'thêmthời gian()',
  `ip` varchar(45) DEFAULT NULL COMMENT 'thao tácIP',
  PRIMARY KEY (`id`),
  KEY `idx_uid` (`uid`),
  KEY `idx_type` (`type`),
  KEY `idx_trano` (`trano`),
  KEY `idx_addtime` (`addtime`)
) ENGINE=InnoDB AUTO_INCREMENT=561 DEFAULT CHARSET=utf8mb4 COMMENT='账变Bản ghiBảng';
/*!40101 SET character_set_client = @saved_cs_client */;

